<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Election Alpha Dashboard</title>
    <script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
    <style>
        :root { --bg: #1a1a2e; --card: #16213e; --text: #e0e0e0; --accent: #0f3460; }
        body { background: var(--bg); color: var(--text); font-family: 'Segoe UI', sans-serif; margin: 0; padding: 20px; }
        .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 20px; }
        .card { background: var(--card); border-radius: 12px; padding: 20px; }
        header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
        h1, h2 { margin-top: 0; }
        table { width: 100%; border-collapse: collapse; }
        th, td { padding: 8px; text-align: left; border-bottom: 1px solid var(--accent); }
        th { cursor: pointer; }
        .heatmap-table { width: 100%; border-collapse: collapse; }
        .heatmap-table td { padding: 5px; text-align: center; }
        canvas { max-width: 100%; }
        select { background: var(--accent); color: var(--text); border: none; padding: 5px; border-radius: 4px; margin-bottom: 10px; }
    </style>
</head>
<body>
    <header>
        <h1>Election Alpha Dashboard</h1>
        <span id="last-refresh"></span>
    </header>
    <div class="grid">
        <div class="card" id="price-panel">
            <h2>Price History</h2>
            <select id="race-selector"></select>
            <canvas id="price-chart"></canvas>
        </div>
        <div class="card" id="arb-panel">
            <h2>Arbitrage Heatmap</h2>
            <div id="arb-heatmap"></div>
        </div>
        <div class="card" id="alpha-panel">
            <h2>Alpha Signals</h2>
            <canvas id="alpha-chart"></canvas>
        </div>
        <div class="card" id="races-panel">
            <h2>Race Summary</h2>
            <table id="race-table">
                <thead>
                    <tr>
                        <th data-sort="race">Race</th>
                        <th data-sort="prob">Latest Prob</th>
                        <th data-sort="delta">24h Delta</th>
                        <th data-sort="platforms">Platforms</th>
                    </tr>
                </thead>
                <tbody></tbody>
            </table>
        </div>
        <div class="card" id="weather-panel">
            <h2>Weather-Price Correlation</h2>
            <canvas id="weather-chart"></canvas>
        </div>
    </div>
    <script>
        const API = '/v1/election';
        let priceChart, alphaChart, weatherChart;

        function escapeHtml(unsafe) {
            if (unsafe === null || unsafe === undefined) return '';
            return unsafe
                 .toString()
                 .replace(/&/g, "&amp;")
                 .replace(/</g, "&lt;")
                 .replace(/>/g, "&gt;")
                 .replace(/"/g, "&quot;")
                 .replace(/'/g, "&#039;");
        }

        function initCharts() {
            const priceCtx = document.getElementById('price-chart');
            priceChart = new Chart(priceCtx, {
                type: 'line',
                data: { datasets: [] },
                options: {
                    responsive: true,
                    scales: {
                        x: { type: 'category', ticks: { color: '#e0e0e0' } },
                        y: { beginAtZero: true, max: 1, ticks: { color: '#e0e0e0' } }
                    },
                    plugins: { legend: { labels: { color: '#e0e0e0' } } }
                }
            });

            const alphaCtx = document.getElementById('alpha-chart');
            alphaChart = new Chart(alphaCtx, {
                type: 'bar',
                data: { labels: [], datasets: [] },
                options: {
                    indexAxis: 'y',
                    responsive: true,
                    scales: {
                        x: { ticks: { color: '#e0e0e0' } },
                        y: { ticks: { color: '#e0e0e0' } }
                    },
                    plugins: { legend: { labels: { color: '#e0e0e0' } } }
                }
            });

            const weatherCtx = document.getElementById('weather-chart');
            weatherChart = new Chart(weatherCtx, {
                type: 'scatter',
                data: { datasets: [] },
                options: {
                    responsive: true,
                    scales: {
                        x: { title: { display: true, text: 'Turnout Score', color: '#e0e0e0' }, ticks: { color: '#e0e0e0' } },
                        y: { title: { display: true, text: 'Market Price', color: '#e0e0e0' }, ticks: { color: '#e0e0e0' } }
                    },
                    plugins: { legend: { labels: { color: '#e0e0e0' } } }
                }
            });
        }

        async function fetchPriceHistory(raceId) {
            if (!raceId) return;
            try {
                const res = await fetch(`${API}/chart/price-history/${raceId}`);
                const data = await res.json();

                const datasets = [];
                const colors = ['#ff6384', '#36a2eb', '#cc65fe', '#ffce56'];
                let colorIdx = 0;

                let allLabels = new Set();

                for (const [platform, points] of Object.entries(data.platforms)) {
                    points.forEach(p => allLabels.add(p.ts));
                }

                const sortedLabels = Array.from(allLabels).sort();

                for (const [platform, points] of Object.entries(data.platforms)) {
                    const dataPoints = sortedLabels.map(label => {
                        const point = points.find(p => p.ts === label);
                        return point ? point.price : null;
                    });

                    datasets.push({
                        label: escapeHtml(platform),
                        data: dataPoints,
                        borderColor: colors[colorIdx % colors.length],
                        fill: false,
                        spanGaps: true
                    });
                    colorIdx++;
                }

                priceChart.data.labels = sortedLabels.map(l => {
                    const d = new Date(l);
                    return `${d.getMonth()+1}/${d.getDate()} ${d.getHours()}:${d.getMinutes().toString().padStart(2, '0')}`;
                });
                priceChart.data.datasets = datasets;
                priceChart.update();
            } catch (e) {
                console.error(e);
            }
        }

        async function fetchArbHeatmap() {
            try {
                const res = await fetch(`${API}/chart/arb-heatmap`);
                const data = await res.json();

                const container = document.getElementById('arb-heatmap');
                container.innerHTML = ''; 

                const table = document.createElement('table');
                table.className = 'heatmap-table';

                const thead = document.createElement('thead');
                const headerRow = document.createElement('tr');
                headerRow.appendChild(document.createElement('th')); 

                data.dates.forEach(date => {
                    const th = document.createElement('th');
                    th.textContent = date;
                    headerRow.appendChild(th);
                });
                thead.appendChild(headerRow);
                table.appendChild(thead);

                const tbody = document.createElement('tbody');
                data.races.forEach((race, i) => {
                    const row = document.createElement('tr');
                    const th = document.createElement('th');
                    th.textContent = race;
                    row.appendChild(th);

                    data.matrix[i].forEach(val => {
                        const td = document.createElement('td');
                        td.textContent = val.toFixed(2) + '%';

                        let color = 'transparent';
                        if (val > 0) {
                            const intensity = Math.min(val / 5, 1);
                            color = `rgba(0, 255, 0, ${intensity})`;
                        } else if (val < 0) {
                            const intensity = Math.min(Math.abs(val) / 5, 1);
                            color = `rgba(255, 0, 0, ${intensity})`;
                        }
                        td.style.backgroundColor = color;

                        row.appendChild(td);
                    });
                    tbody.appendChild(row);
                });
                table.appendChild(tbody);
                container.appendChild(table);
            } catch (e) {
                console.error(e);
            }
        }

        async function fetchAlphaSignals() {
            try {
                const res = await fetch(`${API}/alpha-signals`);
                let data;
                if (res.ok) {
                    data = await res.json();
                } else {
                    data = [
                        { race: 'PA Senate', prob_change: 0.05, confidence: 0.8 },
                        { race: 'AZ Governor', prob_change: -0.03, confidence: 0.6 },
                        { race: 'GA Senate', prob_change: 0.02, confidence: 0.9 }
                    ];
                }

                alphaChart.data.labels = data.map(d => escapeHtml(d.race));
                alphaChart.data.datasets = [{
                    label: 'Predicted Prob Change',
                    data: data.map(d => d.prob_change),
                    backgroundColor: data.map(d => `rgba(54, 162, 235, ${d.confidence})`)
                }];
                alphaChart.update();
            } catch (e) {
                console.error(e);
            }
        }

        async function fetchRaceSummary() {
            try {
                const res = await fetch(`${API}/races`);
                let data;
                if (res.ok) {
                    data = await res.json();
                } else {
                    data = [
                        { state: 'PA', office: 'Senate', latest_probability: 0.55, previous_probability: 0.53, platform_count: 3 },
                        { state: 'AZ', office: 'Governor', latest_probability: 0.48, previous_probability: 0.49, platform_count: 2 },
                        { state: 'GA', office: 'Senate', latest_probability: 0.51, previous_probability: 0.51, platform_count: 4 }
                    ];
                }

                const tbody = document.querySelector('#race-table tbody');
                tbody.innerHTML = '';

                data.forEach(row => {
                    const tr = document.createElement('tr');

                    const tdRace = document.createElement('td');
                    tdRace.textContent = `${row.state} ${row.office}`;
                    tr.appendChild(tdRace);

                    const tdProb = document.createElement('td');
                    tdProb.textContent = (row.latest_probability * 100).toFixed(1) + '%';
                    tr.appendChild(tdProb);

                    const delta = row.latest_probability - (row.previous_probability || row.latest_probability);
                    const tdDelta = document.createElement('td');
                    tdDelta.textContent = (delta > 0 ? '+' : '') + (delta * 100).toFixed(1) + '%';
                    tr.appendChild(tdDelta);

                    const tdPlat = document.createElement('td');
                    tdPlat.textContent = row.platform_count || 2;
                    tr.appendChild(tdPlat);

                    tbody.appendChild(tr);
                });
            } catch (e) {
                console.error(e);
            }
        }

        async function fetchWeatherScatter() {
            try {
                const res = await fetch(`${API}/chart/weather-scatter/2024`);
                const data = await res.json();

                const datasets = [];
                const states = [...new Set(data.map(d => d.state))];
                const colors = ['#ff6384', '#36a2eb', '#cc65fe', '#ffce56', '#4bc0c0'];

                states.forEach((state, i) => {
                    const stateData = data.filter(d => d.state === state);
                    datasets.push({
                        label: escapeHtml(state),
                        data: stateData.map(d => ({
                            x: d.turnout_score,
                            y: d.market_price,
                            race_label: d.race_label
                        })),
                        backgroundColor: colors[i % colors.length]
                    });
                });

                weatherChart.data.datasets = datasets;
                weatherChart.options.plugins = {
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                const point = context.raw;
                                return `${escapeHtml(point.race_label)}: Turnout ${point.x}, Price ${point.y}`;
                            }
                        }
                    },
                    legend: { labels: { color: '#e0e0e0' } }
                };
                weatherChart.update();
            } catch (e) {
                console.error(e);
            }
        }

        async function populateRaceSelector() {
            try {
                const res = await fetch(`${API}/races`);
                let races;
                if (res.ok) {
                    races = await res.json();
                } else {
                    races = [
                        { id: 1, state: 'PA', office: 'Senate', cycle: 2024 },
                        { id: 2, state: 'AZ', office: 'Governor', cycle: 2024 }
                    ];
                }

                const selector = document.getElementById('race-selector');
                selector.innerHTML = '';
                races.forEach(r => {
                    const opt = document.createElement('option');
                    opt.value = r.id;
                    opt.textContent = `${r.state} ${r.office} ${r.cycle}`;
                    selector.appendChild(opt);
                });

                selector.addEventListener('change', (e) => {
                    fetchPriceHistory(e.target.value);
                });

                if (races.length > 0) {
                    fetchPriceHistory(races[0].id);
                }
            } catch (e) {
                console.error(e);
            }
        }

        async function refreshData() {
            document.getElementById('last-refresh').textContent = `Last refresh: ${new Date().toLocaleTimeString()}`;

            const raceId = document.getElementById('race-selector').value;
            if (raceId) fetchPriceHistory(raceId);

            fetchArbHeatmap();
            fetchAlphaSignals();
            fetchRaceSummary();
            fetchWeatherScatter();
        }

        document.addEventListener('DOMContentLoaded', () => {
            initCharts();
            populateRaceSelector().then(() => {
                refreshData();
            });

            setInterval(refreshData, 60000);

            document.querySelectorAll('#race-table th').forEach(th => {
                th.addEventListener('click', () => {
                    const table = th.closest('table');
                    const tbody = table.querySelector('tbody');
                    const rows = Array.from(tbody.querySelectorAll('tr'));
                    const index = Array.from(th.parentNode.children).indexOf(th);
                    const isAsc = th.classList.contains('asc');

                    rows.sort((a, b) => {
                        const aVal = a.children[index].textContent.replace('%', '').replace('+', '');
                        const bVal = b.children[index].textContent.replace('%', '').replace('+', '');

                        const aNum = parseFloat(aVal);
                        const bNum = parseFloat(bVal);

                        if (!isNaN(aNum) && !isNaN(bNum)) {
                            return isAsc ? aNum - bNum : bNum - aNum;
                        }
                        return isAsc ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
                    });

                    th.classList.toggle('asc', !isAsc);
                    th.classList.toggle('desc', isAsc);

                    tbody.append(...rows);
                });
            });
        });
    </script>
</body>
</html>
